1	\chapter{The sheaf of relative differentials}
2	\label{chap:differentials}
3	
4	This chapter develops the sheaf of relative K\"ahler differentials $\Omega_{X/S}$ of a morphism of schemes $X \to S$, starting from the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ already available in Mathlib. The output is a quasi-coherent sheaf of $\struct{X}$-modules characterised by its restriction to affine opens: for any affine open $V = \Spec B \subseteq X$ lying over an affine open $U = \Spec A \subseteq S$, the sections satisfy
5	\[
6	  \Omega_{X/S}(V) \;=\; \Omega_{B/A}.
7	\]
8	
9	The downstream role of this chapter is twofold. First, the smoothness hypothesis on the curve $C \to \Spec k$ that appears in the Jacobian definition and the Abel--Jacobi map amounts to the condition that $\Omega_{C/k}$ is locally free of rank one; this characterisation is what unlocks the dimension computation $g(C) = \dim_k H^0(C, \Omega_{C/k}) = \dim_k H^1(C, \struct{C})$. Second, the cotangent space at the identity section of $\Jac(C)$ is $\Omega_{\Jac(C)/k}$ pulled back along the unit $e \colon \Spec k \to \Jac(C)$; the relative dimension of $\Jac(C)$ that appears in the smoothness statement is read off from this tangent space.
10	
11	\section{The relative cotangent sheaf}
12	
13	\begin{definition}\leanok
14	[Relative cotangent presheaf of a morphism]
15	  \label{def:relative_kaehler_presheaf}
16	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf}
17	  Let $f \colon X \to S$ be a morphism of schemes. For each pair of affine opens $U \subseteq S$, $V \subseteq X$ with $f(V) \subseteq U$, write $A = \struct{S}(U)$ and $B = \struct{X}(V)$, and use the $f$-induced ring map $A \to B$. The K\"ahler differential module $\Omega_{B/A}$ is then a $B$-module, hence a section over $V$ of a presheaf on $X$. The collection of these modules, together with the natural restriction maps along inclusions of affine opens, defines a presheaf of $\struct{X}$-modules on $X$.
18	\end{definition}
19	
20	\begin{theorem}\leanok
21	[Sheaf condition for $\Omega_{X/S}$]
22	  \label{thm:relative_kaehler_isSheaf}
23	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf_isSheaf}
24	  \uses{def:relative_kaehler_presheaf}
25	  The relative cotangent presheaf is a sheaf in the Zariski topology on $X$. The proof reduces to the sheaf condition on the basis of affine basic opens, where it is the localisation compatibility $\Omega_{B[1/f]/A} \cong \Omega_{B/A} \otimes_B B[1/f]$ of the K\"ahler differential module; descent from a basis to all opens is standard.
26	\end{theorem}
27	
28	\begin{definition}\leanok
29	[Relative cotangent sheaf $\Omega_{X/S}$]
30	  \label{def:relative_kaehler_sheaf}
31	  \lean{AlgebraicGeometry.Scheme.relativeDifferentials}
32	  \uses{def:relative_kaehler_presheaf, thm:relative_kaehler_isSheaf}
33	  The sheaf of $\struct{X}$-modules associated with the relative cotangent presheaf is the \emph{sheaf of relative differentials} $\Omega_{X/S}$. It is quasi-coherent.
34	\end{definition}
35	
36	\begin{remark}[Comparison with Mathlib's ring-level $\Omega_{B/A}$]
37	  \label{rem:kahler_compatibility}
38	  Mathlib provides the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ together with the universal derivation $\mathrm{d} \colon B \to \Omega_{B/A}$. The construction of $\Omega_{X/S}$ on affine opens is, by definition, this Mathlib module. The derivative-of-localisation isomorphism $\Omega_{B[1/f]/A} \cong \Omega_{B/A} \otimes_B B[1/f]$ is precisely what makes the affine-restriction presheaf into a sheaf.
39	\end{remark}
40	
41	\section{Universal property and the cotangent exact sequence}
42	
43	\begin{definition}\leanok
44	[Universal derivation]
45	  \label{def:universal_derivation}
46	  \lean{AlgebraicGeometry.Scheme.universalDerivation}
47	  \uses{def:relative_kaehler_sheaf}
48	  The morphism of sheaves of abelian groups $\mathrm{d} \colon \struct{X} \to \Omega_{X/S}$, defined on each affine open $V = \Spec B$ over $\Spec A$ by the Mathlib universal derivation $\mathrm{d}_{B/A} \colon B \to \Omega_{B/A}$, is the \emph{universal derivation}. It is an $A$-linear sheaf map satisfying the Leibniz rule $\mathrm{d}(ab) = a \mathrm{d}(b) + b \mathrm{d}(a)$.
49	\end{definition}
50	
51	The cotangent exact sequence is decomposed into three named ingredients before being assembled into a single theorem.
52	
53	\begin{definition}\leanok
54	[Base-change cotangent map $\alpha$]
55	  \label{def:cotangent_alpha}
56	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqAlpha}
57	  \uses{def:relative_kaehler_sheaf}
58	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{base-change cotangent map} is the natural morphism of quasi-coherent $\struct{X}$-modules
59	  \[
60	    \alpha \colon f^*\Omega_{Y/S} \;\longrightarrow\; \Omega_{X/S}
61	  \]
62	  whose local description on an affine chart with rings $A = \struct{S}(W)$, $A' = \struct{Y}(f(V))$, $B = \struct{X}(V)$ is the standard map $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A}$ of K\"ahler differentials, $da \otimes b \mapsto b \cdot da$.
63	\end{definition}
64	
65	\begin{definition}\leanok
66	[Relative-quotient cotangent map $\beta$]
67	  \label{def:cotangent_beta}
68	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta}
69	  \uses{def:relative_kaehler_sheaf}
70	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{relative-quotient cotangent map} is the natural surjection of quasi-coherent $\struct{X}$-modules
71	  \[
72	    \beta \colon \Omega_{X/S} \;\longrightarrow\; \Omega_{X/Y}
73	  \]
74	  whose local description on an affine chart $A \to A' \to B$ is the surjection $\Omega_{B/A} \to \Omega_{B/A'}$ that kills the $A$-linear derivations factoring through $A'$.
75	\end{definition}
76	
77	\begin{lemma}\leanok
78	[Exactness of the cotangent short complex]
79	  \label{lem:cotangent_exact_structure}
80	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeq_structure}
81	  \uses{def:cotangent_alpha, def:cotangent_beta}
82	  The composition $\beta \circ \alpha$ vanishes, the resulting short complex is exact at the middle term, and $\beta$ is an epimorphism. The three ingredients are local statements whose ring-level inputs are the exactness of the Mathlib cotangent sequence $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$, together with the surjectivity of the right-hand map.
83	\end{lemma}
84	
85	\begin{proof}
86	  \uses{def:cotangent_alpha, def:cotangent_beta, lem:sheafOfModules_epi_of_epi_presheaf, lem:sheafOfModules_exact_iff_stalkwise, lem:derivation_postcomp_comp, lem:cotangent_exact_seq_beta_hη}
87	  \leanok
88	  We dispose of the three claims separately.
89	
90	  \emph{Vanishing $\beta \circ \alpha = 0$.} Inject through the adjunction
91	  $\mathrm{pullback}\,f \dashv \mathrm{pushforward}\,f$, naturality of which converts the equation into one in $Y.\mathrm{Modules}$ of the form $(\hom_{\mathrm{Adj}}\alpha) \cdot (\mathrm{pushforward}\,f).\mathrm{map}\,\beta = 0$. The left-hand side unfolds via the universal property of $\mathrm{relativeDifferentials}'\,\phi$ to a Derivation-valued equality; testing against the canonical derivation $\delta_{\phi}$ reduces the equation pointwise to ``the derivation $\delta_{\phi_2'}$ vanishes on the image of the morphism of presheaves $\phi_2$'', which is the defining property of $\delta_{\phi_2'}$. The composed-adjunction coherence required for the unfolding is the equality $\phi_g' \cdot f^c = \mathrm{unit}\,\phi_{fg}'$ (which is \texttt{rfl} at the Scheme level via $(f \cdot g).c = g.c \cdot \mathrm{pushforward}(g).\mathrm{map}\,f.c$).
92	
93	  \emph{Exactness at the middle.} The cleanest mathematical argument is stalkwise: exactness of a short complex of sheaves of modules is detected on stalks, and on each stalk one is reduced to the ring-level exactness $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$ provided by Mathlib's \texttt{KaehlerDifferential.exact\_mapBaseChange\_map}. % NOTE (iter-086+iter-087): Both routes for the Lean formalisation are confirmed infrastructurally blocked. (a) The stalkwise route requires \texttt{SheafOfModules.stalkFunctor} and a corresponding exactness-reflection theorem at the module-stalk level, neither of which exists in Mathlib (only \texttt{TopCat.Presheaf.stalkFunctor} at the AddCommGrp level is available). (b) The alternative section-wise route through \texttt{ShortComplex.exact\_map\_iff\_of\_faithful} against the faithful functor $\mathrm{SheafOfModules}\to\mathrm{PresheafOfModules}$ requires building the \texttt{PreservesLeftHomologyOf}/\texttt{PreservesRightHomologyOf} instances for that functor (also absent). The iter-085 attempt at a thin Lean shortcut via a universally-false helper signature was reverted in iter-086. \textbf{This sub-claim is deferred upstream parallel to \texttt{instIsMonoidal\_W}} (which also depends on absent Mathlib infrastructure: \texttt{stalk\_tensorObj} for varying-ring $R_0$); \texttt{case h\_exact} of \texttt{cotangentExactSeq\_structure} remains an open \texttt{sorry} pending upstream Mathlib developments.
94	
95	  \emph{Surjectivity of $\beta$.} Epimorphism is reflected through the faithful forgetful functor $\mathrm{SheafOfModules} \to \mathrm{PresheafOfModules}$: it suffices to show $\beta.\mathrm{val}$ is an epi of presheaves. The latter follows from \texttt{PresheafOfModules.epi\_iff\_surjective} together with the fact that the descent's range contains every generator $d_{\phi_2'} b$ for $b \in \Gamma(X, U)$. Indeed, by the universal property's $\texttt{Universal.fac}$ identity, the descent sends $d_{\phi_{fg}'} b \mapsto d_{\phi_2'} b$, so $d_{\phi_2'} b$ is in the range. By Mathlib's \texttt{KaehlerDifferential.span\_range\_derivation} the span of all $d b$ equals the whole module, so the range equals $\top$, hence the descent is surjective. This argument sidesteps any explicit identification of the bundled descent with \texttt{KaehlerDifferential.map}: it works directly on generators via the universal-property collapse. The reflection step is a small Mathlib-gap-fill (Lemma~\ref{lem:sheafOfModules_epi_of_epi_presheaf} below).
96	\end{proof}
97	
98	% NOTE (iter-086+iter-087): the stalkwise criterion is the cleanest mathematical statement for
99	% the cotangent-exactness argument, but its Lean formalisation requires `SheafOfModules.stalkFunctor`
100	% which is absent from Mathlib. The iter-086 alternative route (section-wise exactness + sheafification
101	% preserves exactness, via `ShortComplex.exact_map_iff_of_faithful`) is also blocked: the required
102	% `PreservesLeftHomologyOf`/`PreservesRightHomologyOf` instances for `SheafOfModules.toPresheaf` are
103	% absent from Mathlib. Both routes are deferred upstream. The `\lean{...}` hint is intentionally
104	% omitted: no Lean object corresponds to this lemma after the iter-085 false-helper revert.
105	\begin{lemma}[Stalkwise detection of exactness for sheaves of modules — mathematical statement only; not formalised]
106	  \label{lem:sheafOfModules_exact_iff_stalkwise}
107	  A short complex of sheaves of $\mathcal R$-modules is exact iff its image under each stalk functor $(-)_x$ is exact in the corresponding category of modules at $x$. This transfers an exactness statement on the sheaf side to a pointwise statement on the ring-of-stalks side, where Mathlib's $\mathrm{KaehlerDifferential}$ exactness becomes directly applicable. \emph{Deferred parallel to \texttt{instIsMonoidal\_W}} — pending an upstream Mathlib formulation of \texttt{SheafOfModules.stalkFunctor} and its exactness-reflection theorem, or of the homology-preservation instances required by the alternative section-wise+sheafification route.
108	\end{lemma}
109	
110	\begin{lemma}[Epimorphism reflection from presheaves to sheaves of modules]
111	  \label{lem:sheafOfModules_epi_of_epi_presheaf}
112	  \lean{SheafOfModules.epi_of_epi_presheaf}
113	  If $f : F \to G$ is a morphism of sheaves of $\mathcal R$-modules whose underlying morphism of presheaves $f.\mathrm{val}$ is an epi, then $f$ itself is an epi. This is immediate from the faithfulness of the forgetful functor $\mathrm{SheafOfModules}\,\mathcal R \to \mathrm{PresheafOfModules}\,\mathcal R.\mathrm{val}$ combined with the general fact that faithful functors reflect epimorphisms.
114	\end{lemma}
115	
116	\begin{lemma}[Postcomposition of a derivation distributes over composition]
117	  \label{lem:derivation_postcomp_comp}
118	  \lean{PresheafOfModules.Derivation.postcomp_comp}
119	  Let $d : R \to M$ be a derivation of presheaves of $\mathcal R$-modules and let $f : M \to N$, $g : N \to P$ be morphisms of presheaves of $\mathcal R$-modules. Then
120	  \[
121	    d.\mathrm{postcomp}(f \circ g) \;=\; (d.\mathrm{postcomp}\,f).\mathrm{postcomp}\,g.
122	  \]
123	  The proof is by Derivation extensionality on each open: both sides evaluate to $g.\mathrm{app}_U \circ f.\mathrm{app}_U \circ d_U$ at section $b$. This is a Mathlib-shape lemma about $\mathrm{Derivation}'$ that is missing from Mathlib's $\mathrm{PresheafOfModules}/\mathrm{Differentials}/\mathrm{Presheaf.lean}$.
124	\end{lemma}
125	
126	\begin{lemma}\leanok
127	[Coherence square underlying the cotangent quotient $\beta$]
128	  \label{lem:cotangent_exact_seq_beta_hη}
129	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta_hη}
130	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is a natural transformation
131	  \[
132	    \eta \colon (g \circ f)^{-1}\struct{S} \;\longrightarrow\; f_{*}(g^{-1}\struct{S})
133	  \]
134	  between sheaves of rings on $X$, satisfying the section-level coherence $\eta \circ \phi_{2}'^{\flat} = \phi_{fg}'^{\flat}$ where $\phi_{2}'^{\flat}$ and $\phi_{fg}'^{\flat}$ are the adjoint transposes of $f^{c}$ and $(g \circ f)^{c}$ respectively. This coherence is what packages the natural map $g \circ f \to g \circ f$ on rings into the descent map underlying $\beta$; exposing it as a top-level lemma makes the descent identification with Mathlib's $\mathrm{KaehlerDifferential.map}$ tractable.
135	\end{lemma}
136	
137	\begin{theorem}
138	
139	
140	\leanok
141	[Cotangent exact sequence for a composition]
142	  \label{thm:cotangent_exact_sequence}
143	  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
144	  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
145	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
146	  \[
147	    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
148	      \Omega_{X/Y} \;\longrightarrow\; 0,
149	  \]
150	  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
151	\end{theorem}
152	
153	\section{Smoothness and local freeness of $\Omega$}
154	
155	\begin{theorem}\leanok
156	[Smoothness in terms of $\Omega$]
157	  \label{thm:smooth_iff_locally_free_omega}
158	  \lean{AlgebraicGeometry.Scheme.smooth_iff_locally_free_omega}
159	  \uses{def:relative_kaehler_sheaf}
160	  Let $f \colon X \to S$ be a finite-presentation morphism of schemes. Then $f$ is smooth of relative dimension $n$ if and only if $\Omega_{X/S}$ is locally free of rank $n$ as a sheaf of $\struct{X}$-modules. The forward direction is the Jacobian criterion; the converse follows from the cotangent exact sequence and Nakayama's lemma applied at each point.
161	\end{theorem}
162	
163	\begin{corollary}\leanok
164	[Cotangent space at a section]
165	  \label{cor:cotangent_at_section}
166	  \lean{AlgebraicGeometry.Scheme.cotangent_at_section}
167	  \uses{thm:smooth_iff_locally_free_omega}
168	  If $f \colon X \to S$ is smooth of relative dimension $n$ and $s \colon S \to X$ is a section of $f$, then the cotangent space $s^*\Omega_{X/S}$ is a locally free $\struct{S}$-module of rank $n$. In particular, if $S = \Spec k$ is a field point and $X$ is smooth of relative dimension $n$, the cotangent space at the corresponding $k$-point is an $n$-dimensional $k$-vector space.
169	\end{corollary}
170	
171	\section{Curves and the canonical sheaf}
172	
173	The case of a smooth proper curve $C \to \Spec k$ is the special case $n = 1$: the relative cotangent sheaf $\Omega_{C/k}$ is a line bundle on $C$, classically denoted $\omega_C$ and called the \emph{canonical sheaf}.
174	
175	\begin{theorem}\leanok
176	[Serre-duality genus equality]
177	  \label{thm:serre_duality_genus}
178	  \lean{AlgebraicGeometry.Scheme.serre_duality_genus}
179	  \uses{def:relative_kaehler_sheaf}
180	  Let $C$ be a smooth proper geometrically irreducible curve over a field $k$. Then
181	  \[
182	    \dim_k H^0(C, \Omega_{C/k}) \;=\; \dim_k H^1(C, \struct{C}).
183	  \]
184	  Both sides equal the genus $g(C)$. The equality is the dimension one case of Serre duality applied to the canonical sheaf; combined with the definition $g(C) = \dim_k H^1(C, \struct{C})$, this provides the alternative differential-theoretic characterisation used when computing the relative dimension of $\Jac(C)$ at the identity.
185	\end{theorem}
